+
+function camelCase(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, char: string) => char.toUpperCase());
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (isPlainObject(child)) {
+      Object.assign(result, flatten(child, name));
+    } else {
+      result[name] = child;
+    }
+  }
+  return result;
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return !!value && typeof value === "object" && !Array.isArray(value) &&
+    Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function coerce(value: string): string | boolean | number {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)(?:e[+-]?\\d+)?$/i.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+/** Parse the simple key=value syntax used by `.rc` config files. */
+export function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const equals = line.indexOf("=");
+    if (equals < 1) throw new Error(`Invalid RC line: ${rawLine}`);
+    const key = line.slice(0, equals).trim();
+    let value = line.slice(equals + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) {
+        throw new Error(`Unterminated quoted value for "${key}".`);
+      }
+      value = value.slice(1, -1);
+    }
+    result[camelCase(key)] = coerce(value);
+  }
+  return result;
+}
+
+async function readText(path: string): Promise<string | undefined> {
+  const { Deno } = globalThis as any;
+  try {
+    if (Deno) return await Deno.readTextFile(path);
+    const fs = await import("node:fs/promises");
+    return await fs.readFile(path, "utf8");
+  } catch (error) {
+    if ((error as { code?: string }).code === "ENOENT" ||
+      error instanceof Deno?.errors?.NotFound) return undefined;
+    throw error;
+  }
+}
