+/** Locate, parse and flatten config files according to command config options. */
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths?.length ? options.searchPaths : [cwd()];
+  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
+  const values: Record<string, unknown> = {};
+  let configPath: string | undefined;
+
+  for (const searchPath of paths) {
+    let found = false;
+    for (const format of formats) {
+      const path = resolve(join(searchPath, fileName(options.name, format)));
+      const content = await readText(path);
+      if (content === undefined) continue;
+      found = true;
+      try {
+        const parsed = options.parser
+          ? options.parser(content)
+          : format === ".json" ? JSON.parse(content) : parseRc(content);
+        if (!isPlainObject(parsed)) throw new Error("Config must contain a plain object.");
+        const flattened = flatten(parsed);
+        for (const [key, value] of Object.entries(flattened)) {
+          if (!(key in values)) values[key] = value;
+        }
+      } catch (error) {
+        throw new ConfigParseError(path, error);
+      }
+      configPath ??= path;
+      break;
+    }
+    if (found && !options.mergeConfigs) break;
+  }
+  return { path: configPath, values };
+}
