+async function withDirectory(
+  files: Record<string, string>,
+  fn: (directory: string) => Promise<void>,
+) {
+  const directory = await Deno.makeTempDir();
+  try {
+    await Promise.all(
+      Object.entries(files).map(([name, content]) =>
+        Deno.writeTextFile(`${directory}/${name}`, content)
+      ),
+    );
+    await fn(directory);
+  } finally {
+    await Deno.remove(directory, { recursive: true });
+  }
+}
+
+test("command: config loads JSON, flattens values, and respects precedence", async () => {
+  await withDirectory({
+    "app.json": JSON.stringify({
+      enabled: false,
+      count: 0,
+      "output-file": "config.txt",
+      nested: { "log-level": "debug" },
+      tags: ["one", "two"],
+      ignored: true,
+    }),
+  }, async (directory) => {
+    setEnv("COUNT", "2");
+    try {
+      const command = new Command()
+        .throwErrors()
+        .config({ name: "app", searchPaths: [directory] })
+        .option("--enabled", "...")
+        .option("--count <count:number>", "...")
+        .env("COUNT=<count:number>", "...")
+        .option("--output-file <file>", "...")
+        .option("--nested.log-level <level>", "...")
+        .option("--tags <tag>", "...", { collect: true });
+
+      const result = await command.parse(["--count", "3"]);
+      assertEquals(result.options, {
+        enabled: false,
+        count: 3,
+        outputFile: "config.txt",
+        nested: { logLevel: "debug" },
+        tags: ["one", "two"],
+      });
+      assertEquals(command.getConfigPath(), `${directory}/app.json`);
+      assertEquals(command.getConfigValues().count, 0);
+      assertEquals(command.getConfigValues().nested.logLevel, "debug");
+    } finally {
+      deleteEnv("COUNT");
+    }
+  });
+});
